const RENAME_FUNCTIONS = ['rebuildProgress','initialWeight','normalizeActiveSession','initialReps','makeActiveEntry','formatLogShort','nextTargetLabel','renderFocusLogPanel','syncDraftFromInputs','logSet','analyzeExercise','renderCompletion'];

function renameFunction(source, name) {
  const expression = new RegExp(`function\\s+${name}\\s*\\(`);
  if (!expression.test(source)) throw new Error(`Patch target missing: ${name}`);
  return source.replace(expression, `function ${name}Base343(`);
}

function transformIndex(source) {
  if (!source || source.includes('NEXSET_350_TRANSFORMED')) return source;
  let html = source
    .replaceAll('nexset-3.4.2', 'nexset-3.5.0')
    .replaceAll('3.4.2', '3.5.0');
  try {
    for (const name of RENAME_FUNCTIONS) html = renameFunction(html, name);
    const listener = /document\.addEventListener\(\s*['"]click['"]\s*,\s*event\s*=>/;
    if (!listener.test(html)) throw new Error('Click listener injection point missing');
    html = html.replace(listener, `${PATCH_JS}
document.addEventListener('click',event=>`);
    if (!html.includes('</head>')) throw new Error('Head injection point missing');
    html = html.replace('</head>', `<style data-nexset-patch="3.5.0">${PATCH_CSS}</style></head>`);
    return html;
  } catch (error) {
    console.error('NEXSET 3.5.0 transform failed; serving the safe 3.4.2 shell.', error);
    return source;
  }
}

async function fetchSource(request) {
  const cache = await caches.open(CACHE_NAME);
  try {
    const response = await fetch(request, { cache:'no-store' });
    if (response && response.ok) {
      await cache.put(SOURCE_KEY, response.clone());
      return response;
    }
  } catch (_) {}
  return (await cache.match(SOURCE_KEY)) || (await caches.match('./index.html')) || (await caches.match('./'));
}

async function transformedNavigation(request) {
  const sourceResponse = await fetchSource(request);
  if (!sourceResponse) return new Response('NEXSET is unavailable offline until it has opened once online.', { status:503, headers:{'Content-Type':'text/plain; charset=utf-8'} });
  const source = await sourceResponse.text();
  const transformed = transformIndex(source);
  const headers = new Headers(sourceResponse.headers);
  headers.set('Content-Type','text/html; charset=utf-8');
  headers.set('Cache-Control','no-store');
  headers.delete('Content-Length');
  headers.delete('Content-Encoding');
  return new Response(transformed, { status:200, statusText:'OK', headers });
}

self.addEventListener('install', event => {
  event.waitUntil((async () => {
    const cache = await caches.open(CACHE_NAME);
    await cache.addAll(CORE_ASSETS);
    await Promise.allSettled(OPTIONAL_ASSETS.map(asset => cache.add(asset)));
    try {
      const source = await fetch('./index.html?nexset-source=3.4.2', { cache:'no-store' });
      if (source.ok) await cache.put(SOURCE_KEY, source.clone());
    } catch (_) {}
  })());
});

self.addEventListener('activate', event => {
  event.waitUntil((async () => {
    const keys = await caches.keys();
    await Promise.all(keys.filter(key => key.startsWith(CACHE_PREFIX) && key !== CACHE_NAME).map(key => caches.delete(key)));
    await self.clients.claim();
  })());
});

self.addEventListener('message', event => {
  if (event.data?.type === 'SKIP_WAITING') self.skipWaiting();
});

self.addEventListener('fetch', event => {
  const request = event.request;
  if (request.method !== 'GET') return;
  const url = new URL(request.url);
  if (url.origin !== self.location.origin) return;
  if (request.mode === 'navigate') {
    event.respondWith(transformedNavigation(request));
    return;
  }
  event.respondWith((async () => {
    const cached = await caches.match(request);
    if (cached) return cached;
    try {
      const response = await fetch(request);
      if (response && response.ok) {
        const cache = await caches.open(CACHE_NAME);
        cache.put(request, response.clone());
      }
      return response;
    } catch (_) {
      return cached || Response.error();
    }
  })());
});
